                "location": ["荒野森林", "王城训练场", "B寝宫", "边境公会", "小镇酒馆"],
                "event": "穿越初期至冒险起步",
                "logic": ["起点", "羁绊建立", "秘密", "成长", "里程碑", "道具获取"],
                "causality": "Chain"
